const payload = $input.first().json;
const event = payload.event_type;
const job = payload.job;

// Build message based on event
const templates = {
  'job_assigned': {
    body: `Hi ${job.cleaner_name || 'there'}, you've been assigned a job.

Date: ${job.scheduled_at}
Address: ${job.property_address}
Duration: ${job.duration_minutes} mins

Reply START when you're on your way. Reply HERE when you arrive. Reply DONE when finished.`,
    fallback_subject: 'New Job Assignment - ScratchSolid'
  },
  'job_reminder': {
    body: `Reminder: Your cleaning job is scheduled for ${job.scheduled_at}.

Address: ${job.property_address}
Access code: ${job.access_code || 'N/A'}

Please reply START when leaving.`,
    fallback_subject: 'Job Reminder - ScratchSolid'
  },
  'job_completed': {
    body: `Great work! Job ${job.id} is marked complete.

Thank you for your service.`,
    fallback_subject: 'Job Complete - ScratchSolid'
  },
  'payment_received': {
    body: `Payment confirmed for job ${job.id}. Thank you!`,
    fallback_subject: 'Payment Confirmed - ScratchSolid'
  },
  'default': {
    body: payload.message || 'Notification from ScratchSolid.',
    fallback_subject: 'ScratchSolid Notification'
  }
};

const selected = templates[event] || templates['default'];
return {
  json: {
    phone: payload.phone,
    message: selected.body,
    template_name: payload.template_name || null,
    fallback_email: payload.email,
    fallback_subject: selected.fallback_subject,
    job_id: job?.id
  }
};

const res = $input.first().json;
if (res.sent_via === 'whatsapp') {
  return { json: { status: 'delivered', channel: 'whatsapp', trace_id: res.traceId } };
}
if (res.sent_via === 'email') {
  return { json: { status: 'email_fallback', channel: 'email', reason: res.reason, trace_id: res.traceId } };
}
return { json: { status: 'failed', error: res.error || 'unknown' } };
